import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface CurrentTrip {
  destination: string;
  estimatedTime: number;
  trafficLevel: string;
  distance: string;
}

interface AlternativeRoute {
  routeName: string;
  estimatedTime: number;
  trafficLevel: string;
}

interface CommuteData {
  currentTrip: CurrentTrip;
  alternativeRoutes: AlternativeRoute[];
}

export default function Widget() {
  const commuteData = response.data as CommuteData;
  const { currentTrip, alternativeRoutes } = commuteData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} color="primary">
              Commute to {currentTrip.destination}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Time: {currentTrip.estimatedTime} mins
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Traffic: {currentTrip.trafficLevel}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Distance: {currentTrip.distance}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1 }}>
              Alternative Routes
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {alternativeRoutes.map((route, index) => (
                <Chip
                  key={index}
                  label={`${route.routeName} (${route.estimatedTime} mins, ${route.trafficLevel})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#E0E7FF' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
